 342→        # Double ESC to add sudo
 343→        sudo-command-line() {
 344→          [[ -z $BUFFER ]] && zle up-history
 345→          if [[ $BUFFER == sudo\ * ]]; then
 346→            LBUFFER="''${LBUFFER#sudo }"
 347→          else
 348→            LBUFFER="sudo $LBUFFER"
 349→          fi
 350→        }
 351→        zle -N sudo-command-line
 352→        bindkey '\e\e' sudo-command-line
