 354→        # ghq + fzf integration (Ctrl+g)
 355→        ghq-fzf() {
 356→          local repo=$(ghq list | fzf --preview "eza --tree --level=1 --color=always $(ghq root)/{}" --height=50%)
 357→          if [[ -n "$repo" ]]; then
 358→            cd "$(ghq root)/$repo"
 359→            zle reset-prompt
 360→          fi
 361→        }
 362→        zle -N ghq-fzf
 363→        bindkey '^g' ghq-fzf
 364→
 365→        # Extract function - universal archive extractor
 366→        extract() {
 367→          if [[ -f $1 ]]; then
 368→            case $1 in
 369→              *.tar.bz2)   tar xjf $1    ;;
 370→              *.tar.gz)    tar xzf $1    ;;
 371→              *.tar.xz)    tar xJf $1    ;;
 372→              *.bz2)       bunzip2 $1    ;;
 373→              *.rar)       unrar x $1    ;;
 374→              *.gz)        gunzip $1     ;;
 375→              *.tar)       tar xf $1     ;;
 376→              *.tbz2)      tar xjf $1    ;;
 377→              *.tgz)       tar xzf $1    ;;
 378→              *.zip)       unzip $1      ;;
 379→              *.Z)         uncompress $1 ;;
 380→              *.7z)        7z x $1       ;;
 381→              *.zst)       unzstd $1     ;;
 382→              *)           echo "'$1' cannot be extracted" ;;
 383→            esac
 384→          else
 385→            echo "'$1' is not a valid file"
 386→          fi
 387→        }
